#include<stdio.h>
#define MOD 1000000007LL
long long pw(long long a,long long b){long long r=1;a%=MOD;while(b>0){if(b&1)r=r*a%MOD;a=a*a%MOD;b>>=1;}return r;}
int main(){int n;scanf("%d",&n);long long c=1;for(int i=0;i<n;i++)c=c*2%(MOD)*(2*i+1)%MOD*pw(i+2,MOD-2)%MOD;printf("%lld\n",c);}
